INSERT INTO `harmonisasi` (`judul_rancangan`, `pemrakarsa`, `pemerintah_daerah`, `tanggal_surat_diterima`, `tanggal_rapat`, `pemegang_draf`, `status`, `alasan_pengembalian_draf`, `id_pengguna`) VALUES ('Ranperkada Kota Palopo tentang Perubahan Kedua atas Peraturan Wali Kota Nomor 14 Tahun 2023 tentang Besaran Tunjangan Perumahan dan Transportasi Pimpinan dan Anggota Dewan Perwakilan Rakyat Daerah serta  Standar Kebutuhan Minimal Rumah Tangga Pimpinan', 'Bagian Keuangan Sekretariat Daerah', 'Kota Palopo', '2025-01-23', '2025-02-06', 'Asryani', 'Dikembalikan', '1. Perubahan Besaran Tunjangan Perumahan Pimpinan Dewan Perwakilan Rakyat Daerah Kota Palopo dan Anggota Dewan Perwakilan Rakyat Daerah Kota Palopo mengalami kenaikan yang sangat tinggi dari besaran yang sebelumnya Rp.9.342.000,00 menjadi Rp. 10.031.625,00 untuk Pimpinan DPRD dan Rp.8.025.300,00 bagi Anggota DPRD. Kenaikan tunjangan tersebut perlu dikaji ulang mengingat efiiensi anggaran saat ini sehingga akan membebani keuangan daerah.  2. Besaran tunjangan perumahan dan transportasi pimpinan dan anggota DPRD perlu dihitung ulang oleh Pemerintah Daerah Kota Palopo bersama Tim Appraisal untuk mencegah pemulangan anggaran berdasarkan temuan dari Badan Pemeriksa Keuangan.  3. Besaran tunjangan perumahan dan transportasi Pimpinan dan Anggota Dewan Perwakilan Rakyat Daerah Kota Palopo harus diatur dalam Peraturan Kepala Daerah, bukan diturunkan ke Surat Keputusan Kepala Daerah sebagaimana diamanatkan dalam Peraturan Pemerintah Nomor 18 Tahun 2017 tentang Hak Keuangan dan Administratif Pimpinan dan Anggota Dewan Perwakilan Rakyat Daerah.', NULL);
