INSERT INTO `harmonisasi` (`judul_rancangan`, `pemrakarsa`, `pemerintah_daerah`, `tanggal_surat_diterima`, `tanggal_rapat`, `pemegang_draf`, `status`, `alasan_pengembalian_draf`, `id_pengguna`) VALUES ('Ranperda Kota Parepare tentang Pembentukan Produk Hukum Daerah', 'DPRD', 'Kota Parepare', '2025-06-19', '2025-06-26', 'Rugaya', 'Dikembalikan', 'Telah terdapat regulasi di tingkat nasional yang secara normatif maupun operasional mengatur mengenai pembentukan produk hukum daerah. Oleh karena itu, tidak diperlukan lagi pembentukan peraturan daerah yang baru terkait hal tersebut, mengingat substansinya telah diakomodasi secara memadai dalam peraturan perundang-undangan yang lebih tinggi', NULL);
